form:Form.form:Scripts:
		var CFG;
var TIT=null;   
var zoom;
var cut; 
var copy;

function ReplaceResource(recID)
{
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}


///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function OnLoad()
{        
	zoom=2;         
	cut=0;

	//Cargo la Configuracion
	CFG=new NomadXML(Ctrl("main").getResource("QRY_CFG"));

	//Modifico los Recursos
	ReplaceResource("QRY_IDS_PARENT");

	//Actualizo el Titulo
	if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
	{
		if (TIT==null)
			TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

		if (TIT!=null) TIT=TIT.FirstChild();
		if (TIT!=null && TIT.GetAttr("descr")!="")
			Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	}     

	//Actualizo la Pantalla
	RefreshReport();
}

function ZoomIn()
{                
	if (zoom>0)
	{ 
		zoom--;        
		RefreshReport();
	}
}

function ZoomOut()
{                
	if (zoom<6)
	{ 
		zoom++;        
		RefreshReport();
	}
}

function RefreshReport()
{
	//Actualizo el URL
	Ctrl("REPORT_ORG").SetURL("../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.Organigrama.rpt&ut="+GetProxy().UserToken()+"&mode="+Ctrl("main").GetMode()+"&id="+Ctrl("PARENT").GetXValue()+"&zoom="+zoom+"&cut="+cut+"&now="+datetime2str(new Date()));
}                                        

function RolesContexMenu(MyID,code,event,wind)
{                                 
	callWindow=wind;
	Ctrl("ROLE_CM").SetXValue(MyID);            
	Ctrl("ROLE_CM").EnabledContextMenu("EDIT"  ,(MyID==0                 ?false:true))
	Ctrl("ROLE_CM").EnabledContextMenu("DELETE",(MyID==0 || code=='OWNER'?false:true))
	Ctrl("ROLE_CM").OnContextMenu(event);
}
function EstructContexMenu(MyID,MyCOD,event,wind)
{                                     
	callWindow=wind;
	Ctrl("ESTR_CM").SetXValue(MyID+":"+MyCOD);
	Ctrl("ESTR_CM").OnContextMenu(event);
}
function NewEstructContexMenu(MyParent,MyOrder,event,wind)
{
	callWindow=wind;
	Ctrl("NEW_ESTR_CM").SetXValue(MyParent+":"+MyOrder);
	Ctrl("NEW_ESTR_CM").EnabledContextMenu("PASTE",(cut!=0?true:false))
	Ctrl("NEW_ESTR_CM").OnContextMenu(event);
}


////////////////////////////////////////////////////////////////////////////////////////////////
// ACTORES
function ActorAdd(Obj)
{                   
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","ADD",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'"/>',new FlowResult(),"L");
}
function ActorEdit(Obj)
{
	if (Obj.GetXValue()=="0") return;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","EDIT",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue()+'" />',new FlowResult(),"L");
}
function ActorDelete(Obj)
{
	if (Obj.GetXValue()=="0") return;  

  	var rolVal;  
	var nSQL = GetProxy().SQLService();
	rolVal = nSQL.GetXML(Ctrl("main").getResource("QRY_ROL_USOWF"), "<PARAM oi_organigrama=\""+Ctrl("PARENT").GetXValue()+"\" oi_role=\""+Obj.GetXValue()+"\"/>");

	if(rolVal.GetAttr("flag") != "1")
	{	
		if (confirm("¿Esta seguro que desea Eliminar el Actor?"))
			openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","DEL",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue()+'" />',new FlowResult(),"L");
	}
	else
	{
		alert("No puede eliminar el Actor, ya que está siendo utilizado dentro de un nodo de un WF que utiliza éste ORG");
	}
}       

////////////////////////////////////////////////////////////////////////////////////////////////
// ESTRUCTURAS                            
function EstructuraExpand(Obj)
{                        
	callWindow.ExpandContract(Obj.GetXValue().split(":")[0]);
}

function EstructuraAdd(Obj)
{                                  
	cut=0;              
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","ADD",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ESTR-PARENT="'+(Obj.GetXValue().split(":")[0]=="0"?"":Obj.GetXValue().split(":")[0])+'" ORDER="'+Obj.GetXValue().split(":")[1]+'" />',new FlowResult(),"L");
}
function EstructuraEdit(Obj)
{                   
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","EDIT",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraDelete(Obj)
{
	cut=0;
	if (confirm("¿Esta seguro que desea Eliminar el Nodo?"))
		openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","DEL",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraLeft(Obj)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","LEFT",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraRight(Obj)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","RIGHT",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraUp(Obj)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","UP",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraDown(Obj)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","DOWN",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ID="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}
function EstructuraPaste(Obj)
{         
	if (cut==0) return;    

	if (copy)
		openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","COPY" ,'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ESTR-PARENT="'+(Obj.GetXValue().split(":")[0]=="0"?"":Obj.GetXValue().split(":")[0])+'" ORDER="'+Obj.GetXValue().split(":")[1]+'" ID="'+cut+'" />',new FlowResult(),"L");
	else
		openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.flow","PASTE",'<PARAM PARENT="'+Ctrl("PARENT").GetXValue()+'" ESTR-PARENT="'+(Obj.GetXValue().split(":")[0]=="0"?"":Obj.GetXValue().split(":")[0])+'" ORDER="'+Obj.GetXValue().split(":")[1]+'" ID="'+cut+'" />',new FlowResult(),"L");
	cut=0;
}

function EntidadesAddDel(Obj)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ENTIDAD_ESTR.MAIN.STD.flow","ADDDEL",'<PARAM PARENT="'+Obj.GetXValue().split(":")[0]+'" />',new FlowResult(),"L");
}

function EstructuraCopy(Obj)
{
	copy=true;
	cut=Obj.GetXValue().split(":")[0];

	callWindow.Refresh(null, cut, copy);
}
function EstructuraCut(Obj)
{
	copy=false;                        
	cut=Obj.GetXValue().split(":")[0];  

	callWindow.Refresh(null, cut, copy);
}

function ShowPersonas(MyID)
{
	cut=0;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ENTIDAD_ESTR.MAIN.STD.flow","LIST",'<PARAM PARENT="'+MyID+'" />',new FlowResult(),"L");
}

////////////////////////////////////////////////////////////////////////////////////////////////
function FlowResult()
{
	this.processResult = function(xml)
	{                      
		var RS=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_REFRESH"), '<PARAMS id="'+Ctrl("PARENT").GetXValue()+'" />');
		callWindow.Refresh(RS);
	}
}

function Nothing()
{
}

function OnSearch()
{
	var xmlParam = new NomadXML("PARAM");
	xmlParam.SetAttr("PARENT",Ctrl("PARENT").GetXValue());
	xmlParam.SetAttr("BUSCAR",Ctrl("BUSCAR").GetXValue());

	openNewFlow("NucleusWF.Base.Definicion.Organigramas.ESTRUCTURA.SEARCH.flow","LIST",xmlParam.ToString(),new FlowResult(),"M");
}
